            // Add blocks
            for (const uint256& hash : peer.m_blocks_for_inv_relay) {
                vInv.emplace_back(MSG_BLOCK, hash);
                if (vInv.size() == MAX_INV_SZ) {
                    MakeAndPushMessage(node, NetMsgType::INV, vInv);
                    vInv.clear();
                }
            }
            peer.m_blocks_for_inv_relay.clear();
